blocks.body:
{
    "level": "A1–B1",
    "intro": "У цій темі ти навчишся утворювати <strong>множину іменників<\/strong> в англійській мові, розпізнавати <strong>винятки<\/strong>, а також відрізняти слова, які існують тільки в однині або тільки у множині.",
    "rules": [
        {
            "label": "+ S",
            "color": "emerald",
            "text": "<strong>Більшість іменників<\/strong> утворюють множину додаванням <strong>-s<\/strong>.",
            "example": "cat → cats, pen → pens, car → cars"
        },
        {
            "label": "+ ES",
            "color": "blue",
            "text": "<strong>-es<\/strong> додаємо після <strong>s, ss, x, z, ch, sh<\/strong> і часто після <strong>приголосної + o<\/strong>.",
            "example": "bus → buses, box → boxes, tomato → tomatoes"
        },
        {
            "label": "Y → IES",
            "color": "amber",
            "text": "Після <strong>приголосної + y<\/strong> змінюємо <strong>y → ies<\/strong>.",
            "example": "baby → babies, country → countries"
        },
        {
            "label": "F → VES",
            "color": "rose",
            "text": "Частина іменників на <strong>-f \/ -fe<\/strong> змінює закінчення на <strong>-ves<\/strong>.",
            "example": "knife → knives, wolf → wolves"
        },
        {
            "label": "IRREGULAR",
            "color": "purple",
            "text": "Деякі іменники мають <strong>неправильні форми<\/strong> або взагалі не змінюються.",
            "example": "man → men, child → children, sheep → sheep"
        }
    ]
}

{
    "title": "1. Головні способи утворення множини",
    "intro": "У більшості випадків достатньо знати чотири базові моделі:",
    "items": [
        {
            "label": "+ S",
            "title": "Просто додаємо -s",
            "subtitle": "chair → chairs, notebook → notebooks, apple → apples"
        },
        {
            "label": "+ ES",
            "title": "Додаємо -es",
            "subtitle": "bus → buses, watch → watches, fox → foxes"
        },
        {
            "label": "Y → IES",
            "title": "Змінюємо y на ies",
            "subtitle": "lady → ladies, puppy → puppies, city → cities"
        },
        {
            "label": "F\/FE → VES",
            "title": "Змінюємо f \/ fe на ves",
            "subtitle": "wife → wives, leaf → leaves, knife → knives"
        }
    ]
}

{
    "title": "2. Правило 1: додаємо -s",
    "sections": [
        {
            "label": "Основне правило",
            "color": "emerald",
            "description": "Більшість злічуваних іменників утворюють множину простим <strong>додаванням -s<\/strong>.",
            "examples": [
                {
                    "en": "cat → cats",
                    "ua": "кіт → коти"
                },
                {
                    "en": "pen → pens",
                    "ua": "ручка → ручки"
                },
                {
                    "en": "car → cars",
                    "ua": "машина → машини"
                },
                {
                    "en": "chair → chairs",
                    "ua": "стілець → стільці"
                }
            ]
        },
        {
            "label": "Після голосної",
            "color": "sky",
            "description": "Якщо слово закінчується на голосну або на звичайний приголосний без особливих винятків, також просто додаємо <strong>-s<\/strong>.",
            "examples": [
                {
                    "en": "toy → toys",
                    "ua": "іграшка → іграшки"
                },
                {
                    "en": "day → days",
                    "ua": "день → дні"
                },
                {
                    "en": "radio → radios",
                    "ua": "радіо → радіо"
                },
                {
                    "en": "kangaroo → kangaroos",
                    "ua": "кенгуру → кенгуру"
                }
            ]
        },
        {
            "label": "Узгодження в реченні",
            "color": "amber",
            "description": "У множині іменник змінюється, а звичайне дієслово часто лишається в базовій формі. Важливий виняток — <strong>to be → are<\/strong>.",
            "examples": [
                {
                    "en": "Cats sleep a lot.",
                    "ua": "Коти багато сплять."
                },
                {
                    "en": "My friends live in Lviv.",
                    "ua": "Мої друзі живуть у Львові."
                },
                {
                    "en": "The books are on the table.",
                    "ua": "Книги лежать на столі."
                }
            ],
            "note": "📌 Не додавай -s до дієслова після підмета у множині: правильно <strong>The cats run<\/strong>, а не <strong>The cats runs<\/strong>."
        }
    ]
}

{
    "title": "3. Правило 2: коли додаємо -es",
    "sections": [
        {
            "label": "Після s, ss, x, z, ch, sh",
            "color": "blue",
            "description": "Після шиплячих і свистячих закінчень додаємо <strong>-es<\/strong>, щоб слово було зручно вимовляти.",
            "examples": [
                {
                    "en": "bus → buses",
                    "ua": "автобус → автобуси"
                },
                {
                    "en": "kiss → kisses",
                    "ua": "поцілунок → поцілунки"
                },
                {
                    "en": "box → boxes",
                    "ua": "коробка → коробки"
                },
                {
                    "en": "church → churches",
                    "ua": "церква → церкви"
                },
                {
                    "en": "dish → dishes",
                    "ua": "тарілка → тарілки"
                }
            ]
        },
        {
            "label": "Приголосна + o",
            "color": "purple",
            "description": "Часто після <strong>приголосної + o<\/strong> теж додаємо <strong>-es<\/strong>.",
            "examples": [
                {
                    "en": "tomato → tomatoes",
                    "ua": "помідор → помідори"
                },
                {
                    "en": "potato → potatoes",
                    "ua": "картоплина → картоплини"
                },
                {
                    "en": "hero → heroes",
                    "ua": "герой → герої"
                },
                {
                    "en": "mosquito → mosquitoes",
                    "ua": "комар → комарі"
                }
            ]
        },
        {
            "label": "Винятки на -o",
            "color": "sky",
            "description": "Є слова на <strong>-o<\/strong>, які все ж утворюють множину через <strong>-s<\/strong>.",
            "examples": [
                {
                    "en": "photo → photos",
                    "ua": "фото → фото"
                },
                {
                    "en": "piano → pianos",
                    "ua": "піаніно → піаніно"
                },
                {
                    "en": "radio → radios",
                    "ua": "радіо → радіо"
                },
                {
                    "en": "video → videos",
                    "ua": "відео → відео"
                }
            ],
            "note": "⚠️ Для слів на -o краще перевіряти словник, якщо сумніваєшся."
        }
    ]
}

{
    "title": "4. Правило 3: коли y стає ies",
    "sections": [
        {
            "label": "Приголосна + y",
            "color": "amber",
            "description": "Якщо перед <strong>y<\/strong> стоїть приголосна, змінюємо <strong>y → ies<\/strong>.",
            "examples": [
                {
                    "en": "country → countries",
                    "ua": "країна → країни"
                },
                {
                    "en": "lady → ladies",
                    "ua": "леді \/ жінка → леді \/ жінки"
                },
                {
                    "en": "family → families",
                    "ua": "сім'я → сім'ї"
                },
                {
                    "en": "dictionary → dictionaries",
                    "ua": "словник → словники"
                }
            ]
        },
        {
            "label": "Голосна + y",
            "color": "emerald",
            "description": "Якщо перед <strong>y<\/strong> стоїть голосна, просто додаємо <strong>-s<\/strong>.",
            "examples": [
                {
                    "en": "toy → toys",
                    "ua": "іграшка → іграшки"
                },
                {
                    "en": "boy → boys",
                    "ua": "хлопець → хлопці"
                },
                {
                    "en": "holiday → holidays",
                    "ua": "канікули \/ свято → свята"
                },
                {
                    "en": "monkey → monkeys",
                    "ua": "мавпа → мавпи"
                }
            ]
        },
        {
            "label": "Як не плутатися",
            "color": "sky",
            "description": "Подивися лише на букву перед <strong>y<\/strong>: приголосна → <strong>ies<\/strong>, голосна → <strong>ys<\/strong>.",
            "examples": [
                {
                    "en": "baby → babies",
                    "ua": "приголосна + y"
                },
                {
                    "en": "day → days",
                    "ua": "голосна + y"
                }
            ],
            "note": "📌 Працює в більшості базових випадків рівня A1–A2."
        }
    ]
}

{
    "title": "5. Правило 4: f \/ fe → ves",
    "sections": [
        {
            "label": "Типова заміна",
            "color": "rose",
            "description": "Багато іменників на <strong>-f<\/strong> або <strong>-fe<\/strong> змінюють закінчення на <strong>-ves<\/strong>.",
            "examples": [
                {
                    "en": "wolf → wolves",
                    "ua": "вовк → вовки"
                },
                {
                    "en": "wife → wives",
                    "ua": "дружина → дружини"
                },
                {
                    "en": "knife → knives",
                    "ua": "ніж → ножі"
                },
                {
                    "en": "leaf → leaves",
                    "ua": "листок → листки"
                }
            ]
        },
        {
            "label": "Ще приклади",
            "color": "amber",
            "description": "Ця модель також часто трапляється в поширених словах.",
            "examples": [
                {
                    "en": "life → lives",
                    "ua": "життя → життя \/ життєві випадки"
                },
                {
                    "en": "thief → thieves",
                    "ua": "злодій → злодії"
                },
                {
                    "en": "shelf → shelves",
                    "ua": "полиця → полиці"
                },
                {
                    "en": "half → halves",
                    "ua": "половина → половини"
                }
            ]
        },
        {
            "label": "Винятки",
            "color": "sky",
            "description": "Не всі слова на <strong>-f<\/strong> змінюються на <strong>-ves<\/strong>. Частина додає просто <strong>-s<\/strong>, а деякі мають дві форми.",
            "examples": [
                {
                    "en": "roof → roofs",
                    "ua": "дах → дахи"
                },
                {
                    "en": "chief → chiefs",
                    "ua": "керівник → керівники"
                },
                {
                    "en": "belief → beliefs",
                    "ua": "переконання → переконання"
                },
                {
                    "en": "wharf → wharfs \/ wharves",
                    "ua": "причал → причали"
                }
            ],
            "note": "⚠️ Такі слова краще окремо запам'ятати."
        }
    ]
}

{
    "title": "6. Неправильні форми множини",
    "sections": [
        {
            "label": "Зміна голосної",
            "color": "purple",
            "description": "Деякі іменники утворюють множину через зміну внутрішньої голосної.",
            "examples": [
                {
                    "en": "man → men",
                    "ua": "чоловік → чоловіки"
                },
                {
                    "en": "woman → women",
                    "ua": "жінка → жінки"
                },
                {
                    "en": "foot → feet",
                    "ua": "стопа → стопи"
                },
                {
                    "en": "tooth → teeth",
                    "ua": "зуб → зуби"
                },
                {
                    "en": "goose → geese",
                    "ua": "гусак \/ гуска → гуси"
                },
                {
                    "en": "mouse → mice",
                    "ua": "миша → миші"
                }
            ]
        },
        {
            "label": "Інша форма слова",
            "color": "rose",
            "description": "У деяких словах форма множини зовсім не схожа на форму однини.",
            "examples": [
                {
                    "en": "child → children",
                    "ua": "дитина → діти"
                },
                {
                    "en": "person → people",
                    "ua": "людина → люди"
                },
                {
                    "en": "ox → oxen",
                    "ua": "віл \/ бик → воли"
                },
                {
                    "en": "louse → lice",
                    "ua": "воша → воші"
                }
            ]
        },
        {
            "label": "Класичні форми",
            "color": "amber",
            "description": "Частина наукових або формальних слів зберігає латинські \/ грецькі моделі множини.",
            "examples": [
                {
                    "en": "phenomenon → phenomena",
                    "ua": "феномен → феномени"
                },
                {
                    "en": "criterion → criteria",
                    "ua": "критерій → критерії"
                },
                {
                    "en": "curriculum → curricula",
                    "ua": "навчальний план → навчальні плани"
                }
            ]
        },
        {
            "label": "Форма не змінюється",
            "color": "emerald",
            "description": "Є іменники, у яких форми однини і множини збігаються.",
            "examples": [
                {
                    "en": "fish → fish",
                    "ua": "риба → риби"
                },
                {
                    "en": "sheep → sheep",
                    "ua": "вівця → вівці"
                },
                {
                    "en": "deer → deer",
                    "ua": "олень → олені"
                },
                {
                    "en": "aircraft → aircraft",
                    "ua": "літак → літаки"
                },
                {
                    "en": "species → species",
                    "ua": "вид → види"
                },
                {
                    "en": "shrimp → shrimp",
                    "ua": "креветка → креветки"
                }
            ],
            "note": "📌 Іноді можливі інші форми в спеціальних значеннях, але для базового рівня цього правила достатньо."
        }
    ]
}

{
    "title": "7. Швидка таблиця правил",
    "intro": "Коротке порівняння найважливіших моделей утворення множини:",
    "rows": [
        {
            "en": "Most nouns",
            "ua": "Більшість іменників",
            "note": "+ s: cat → cats, pen → pens"
        },
        {
            "en": "After s, ss, x, z, ch, sh",
            "ua": "Після s, ss, x, z, ch, sh",
            "note": "+ es: box → boxes, church → churches"
        },
        {
            "en": "Consonant + y",
            "ua": "Приголосна + y",
            "note": "y → ies: country → countries"
        },
        {
            "en": "Vowel + y",
            "ua": "Голосна + y",
            "note": "+ s: toy → toys, boy → boys"
        },
        {
            "en": "Many nouns ending in -f \/ -fe",
            "ua": "Багато слів на -f \/ -fe",
            "note": "f \/ fe → ves: knife → knives"
        },
        {
            "en": "Consonant + o",
            "ua": "Приголосна + o",
            "note": "often + es: hero → heroes, potato → potatoes"
        },
        {
            "en": "Irregular plurals",
            "ua": "Неправильні форми",
            "note": "man → men, child → children, mouse → mice"
        },
        {
            "en": "Same singular and plural",
            "ua": "Однакова форма",
            "note": "sheep → sheep, deer → deer"
        }
    ],
    "warning": "📌 Якщо слово виглядає незвично, перевір словник: саме у винятках помиляються найчастіше."
}

{
    "title": "8. Слова, що існують тільки в однині",
    "sections": [
        {
            "label": "Незлічувані іменники",
            "color": "indigo",
            "description": "Незлічувані іменники зазвичай <strong>не мають форми множини<\/strong> і вживаються з дієсловом в однині.",
            "examples": [
                {
                    "en": "water, milk, gold",
                    "ua": "рідини, матеріали"
                },
                {
                    "en": "advice, information, happiness, wisdom",
                    "ua": "абстрактні поняття"
                },
                {
                    "en": "weather, rain, snow",
                    "ua": "явища природи"
                },
                {
                    "en": "coffee, juice, meat",
                    "ua": "їжа і напої"
                }
            ]
        },
        {
            "label": "Науки, мови, види спорту",
            "color": "sky",
            "description": "Такі слова часто виглядають як множина, але граматично поводяться як однина.",
            "examples": [
                {
                    "en": "physics, mathematics, history",
                    "ua": "назви наук"
                },
                {
                    "en": "English, Ukrainian, Chinese",
                    "ua": "назви мов"
                },
                {
                    "en": "aerobics, athletics",
                    "ua": "види спорту \/ активності"
                }
            ]
        },
        {
            "label": "Типові речення",
            "color": "emerald",
            "description": "З такими словами не кажемо <strong>informations<\/strong> або <strong>advices<\/strong> у базовому значенні.",
            "examples": [
                {
                    "en": "The information is useful.",
                    "ua": "Ця інформація корисна."
                },
                {
                    "en": "Her advice was helpful.",
                    "ua": "Її порада була корисною."
                },
                {
                    "en": "The weather is cold today.",
                    "ua": "Сьогодні холодна погода."
                }
            ],
            "note": "📌 У спеціальних контекстах деякі слова можуть мати форму множини, але для стандартних правил вважай їх singular-only."
        }
    ]
}

{
    "title": "9. Слова, що існують лише у множині",
    "sections": [
        {
            "label": "Парні предмети",
            "color": "teal",
            "description": "Деякі предмети, що складаються з двох частин, уживаються тільки у множині. Часто з ними вживають <strong>a pair of<\/strong>.",
            "examples": [
                {
                    "en": "trousers",
                    "ua": "штани"
                },
                {
                    "en": "jeans",
                    "ua": "джинси"
                },
                {
                    "en": "glasses",
                    "ua": "окуляри"
                },
                {
                    "en": "scissors",
                    "ua": "ножиці"
                },
                {
                    "en": "binoculars",
                    "ua": "бінокль"
                },
                {
                    "en": "headphones",
                    "ua": "навушники"
                }
            ]
        },
        {
            "label": "Інші plural-only nouns",
            "color": "purple",
            "description": "Частина іменників позначає сукупність, абстрактні результати або стійкі поняття й теж уживається тільки у множині.",
            "examples": [
                {
                    "en": "savings, earnings, goods",
                    "ua": "заощадження, заробітки, товари"
                },
                {
                    "en": "archives, belongings",
                    "ua": "архіви, речі"
                },
                {
                    "en": "outskirts, surroundings, tropics",
                    "ua": "околиця, околиці \/ тропіки"
                },
                {
                    "en": "congratulations, customs",
                    "ua": "привітання, митниця \/ звичаї"
                }
            ]
        },
        {
            "label": "Зміна значення",
            "color": "amber",
            "description": "Іноді форма однини існує, але означає вже інше слово або інше значення.",
            "examples": [
                {
                    "en": "glasses = окуляри, glass = скло \/ склянка",
                    "ua": "різні значення"
                },
                {
                    "en": "customs = митниця \/ звичаї, custom = звичай",
                    "ua": "різні значення"
                },
                {
                    "en": "trousers are new \/ a pair of trousers",
                    "ua": "правильне узгодження"
                }
            ],
            "note": "📌 Кажемо <strong>These scissors are sharp<\/strong> і <strong>a pair of scissors<\/strong>."
        }
    ]
}

{
    "title": "10. Типові помилки",
    "items": [
        {
            "label": "Помилка 1",
            "color": "rose",
            "title": "Писати -s замість -es після шиплячих і свистячих.",
            "wrong": "boxs, churchs, buss",
            "right": "✅ <span class=\"font-mono\">boxes, churches, buses<\/span>"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Змінювати y після голосної.",
            "wrong": "toies, boies, monkeies",
            "right": "✅ <span class=\"font-mono\">toys, boys, monkeys<\/span>"
        },
